        "plt.plot(t, y_parabola, 'b', label='Saída')  # Plotar resposta (linha azul sólida)\n",
        "\n",
        "plt.title('Resposta à Entrada em Parábola da Função de Transferência em malha fechada T(s)')  # Adicionar título\n",
